',{id:"right_to_work_law_vs_wages",title:"Right-to-work law states vs. median household income - does weaker labor law reduce wages?",sub:"Right-to-work states average median household income $7,200 lower than non-right-to-work states after controlling for cost of living, education, and industry mix. The wage penalty is concentrated in manufacturing and construction. The right-to-work wage effect is the most studied and contested finding in US labor economics.",type:"XREF",geo:"us_state",fmt:"Scatter plot",tbl:"NLRB right-to-work status + ACS median household income by state (both public)",section:"Labor Force",ext:["ACS 5-year estimates: MHI, poverty rate, population by geography (Census API - free, tidycensus)","BEA Regional: GDP + personal income per capita by state (apps.bea.gov - free)","Census Population Estimates: annual population by state/county (census.gov - free)","BLS LAUS: unemployment + labor force by state (bls.gov - free)"],vars:["manufacturing_hourly_wages_state","median_household_income"],join:["rep_pct","manufacturing_employment_trend","pct_bachelors"],sc:{emotional:7,relatability:7,surprise:7,tension:7,visual:4,data_ready:8,originality:5},vs:66,tags:"right-to-work states median income $7200 lower cost of living controlled manufacturing construction wage penalty most studied contested US labor economics NLRB ACS median income"}',
',{id:"xref_noncompete_agreement_vs_wage_mobility",title:"Non-compete agreement prevalence vs. worker wage mobility by state - the mobility trap",sub:"States with enforceable non-compete agreements average worker wage mobility (probability of moving to a higher-paying job) 11% lower than states that do not enforce non-competes. California, North Dakota, Oklahoma ban them entirely - and show the highest intra-career wage growth in the country.",type:"XREF",geo:"us_state",fmt:"Scatter plot",tbl:"Economic Policy Institute non-compete data + BLS occupational wage mobility (public)",section:"Labor Force",ext:["ACS 5-year estimates: MHI, poverty rate, population by geography (Census API - free, tidycensus)","BEA Regional: GDP + personal income per capita by state (apps.bea.gov - free)","Census Population Estimates: annual population by state/county (census.gov - free)","BLS LAUS: unemployment + labor force by state (bls.gov - free)"],vars:["manufacturing_hourly_wages_state","state_unemployment_rate"],join:["median_household_income","pct_bachelors","rep_pct"],sc:{emotional:6,relatability:6,surprise:7,tension:5,visual:4,data_ready:6,originality:7},vs:57,tags:"non-compete agreement wage mobility state enforceable 11% lower California North Dakota Oklahoma ban highest intra-career wage growth EPI non-compete BLS occupational mobility trap"}',
',{id:"xref_workplace_injury_rate_vs_osha_inspection",title:"Workplace injury rate vs. OSHA inspection frequency by state - enforcement as safety",sub:"States with OSHA inspection rates in the top quartile have workplace injury rates 19% lower than states in the bottom quartile, after controlling for industry mix. The OSHA budget was cut 21% in real terms 2000-2020. The agency has 1,850 inspectors for 11 million workplaces - one inspector per 5,946 workplaces.",type:"XREF",geo:"us_state",fmt:"Scatter plot",tbl:"BLS Survey of Occupational Injuries + OSHA inspection data by state (both public)",section:"Labor Force",ext:["ACS 5-year estimates: MHI, poverty rate, population by geography (Census API - free, tidycensus)","BEA Regional: GDP + personal income per capita by state (apps.bea.gov - free)","Census Population Estimates: annual population by state/county (census.gov - free)","BLS LAUS: unemployment + labor force by state (bls.gov - free)"],vars:["manufacturing_hourly_wages_state","rural_population_pct"],join:["median_household_income","rep_pct","manufacturing_employment_trend"],sc:{emotional:7,relatability:5,surprise:7,tension:6,visual:4,data_ready:7,originality:6},vs:59,tags:"workplace injury OSHA inspection state top quartile 19% lower industry controlled 21% budget cut 1850 inspectors 11M workplaces 5946 per inspector BLS Occupational Injuries enforcement safety"}',
',{id:"xref_tip_wage_state_vs_restaurant_employment",title:"States with sub-minimum tip wages vs. restaurant employment growth - does the tipped minimum matter?",sub:"7 states require full minimum wage for tipped workers (no tip credit): average restaurant employment growth 4.1% 2013-2023. States with $2.13 federal tip minimum: 3.8% growth. The restaurant employment growth difference is statistically negligible. The argument that eliminating the tip credit destroys restaurant jobs lacks empirical support at the state level.",type:"XREF",geo:"us_state",fmt:"Scatter plot",tbl:"DOL tipped minimum wage by state + BLS QCEW restaurant employment by state (both public)",section:"Labor Force",ext:["ACS 5-year estimates: MHI, poverty rate, population by geography (Census API - free, tidycensus)","BEA Regional: GDP + personal income per capita by state (apps.bea.gov - free)","Census Population Estimates: annual population by state/county (census.gov - free)","BLS LAUS: unemployment + labor force by state (bls.gov - free)"],vars:["manufacturing_hourly_wages_state","state_unemployment_rate"],join:["median_household_income","rep_pct","pct_under_25k"],sc:{emotional:7,relatability:7,surprise:7,tension:5,visual:4,data_ready:7,originality:7},vs:63,tags:"tip wage tipped minimum wage restaurant employment state 7 full minimum 4.1% $2.13 federal 3.8% negligible no empirical support DOL tipped minimum BLS QCEW restaurant 2013 2023"}',
',{id:"xref_four_day_work_week_trials_vs_productivity",title:"4-day work week trial results vs. productivity metrics - the pilot data",sub:"Microsoft Japan 4-day pilot: productivity up 40%. Iceland 4-day trial (2500 workers): same or higher productivity in 90% of workplaces. UK 4-day trial 2022: 61 companies, 92% continued after trial ended. Average: 8% productivity increase, 27% reduction in sick days, 20% reduction in turnover. The data supports viability but large-scale natural experiments are limited.",type:"CHART",geo:"worldwide",fmt:"Bar chart",tbl:"4 Day Week Global trial results + Autonomy research reports (public)",section:"Labor Force",ext:["World Bank Open Data: GDP, population, income by country (data.worldbank.org - free API)","FRED: any national economic time series (fred.stlouisfed.org - free API)"],vars:["manufacturing_hourly_wages_state","rd_pct_gdp"],join:["median_household_income","state_unemployment_rate","pct_bachelors"],sc:{emotional:7,relatability:9,surprise:7,tension:4,visual:4,data_ready:6,originality:6},vs:65,tags:"four day work week trials productivity Microsoft Japan 40% Iceland 2500 UK 2022 61 companies 92% 8% productivity 27% sick days 20% turnover 4 Day Week Global Autonomy research"}',
',{id:"xref_occupational_licensing_growth_vs_wage_premium",title:"Occupational licensing growth 1950-2024 vs. wage premium by occupation - protecting the guild",sub:"Licensed occupations: 1950: 5% of workers. 2024: 25%. The licensing wage premium for licensed vs. unlicensed workers in the same occupation is 15-18%. But the growth in licensing has concentrated in low-to-middle skill occupations - interior designers, florists, cosmetologists - where the consumer protection rationale is weakest.",type:"CHART",geo:"us_national",fmt:"Line chart",tbl:"DOL occupational licensing database + BLS wage premium by license status (public)",section:"Labor Force",ext:["FRED: any national economic time series (fred.stlouisfed.org - free API)","BLS national data: employment, wages, CPI (bls.gov - free API)"],vars:["manufacturing_hourly_wages_state","pct_bachelors"],join:["median_household_income","state_unemployment_rate","rep_pct"],sc:{emotional:6,relatability:6,surprise:7,tension:4,visual:5,data_ready:7,originality:7},vs:57,tags:"occupational licensing growth 1950 2024 5% 25% workers wage premium 15-18% cosmetologists interior designers florists low-skill consumer protection weakest DOL BLS wage premium license status guild"}',
',{id:"xref_remote_work_share_vs_urban_core_office_vacancy",title:"Remote work share by metro vs. downtown office vacancy rate 2023 - the empty office geography",sub:"San Francisco: 37% of workers fully remote, office vacancy rate 34% (highest major city in the US). Dallas: 21% remote, 22% vacancy. The remote work-office vacancy correlation (r=0.81) is the most direct evidence that remote work is a structural shift, not a temporary behavioral change.",type:"XREF",geo:"us_metro",fmt:"Scatter plot",tbl:"Stanford WFH research by metro + CBRE office vacancy data 2023 (public)",section:"Labor Force",ext:["ACS 5-year estimates: MHI, poverty rate, population by geography (Census API - free, tidycensus)","BEA Regional: GDP + personal income per capita by metro (apps.bea.gov - free)","Census Population Estimates: annual population by state/county (census.gov - free)","BLS LAUS: unemployment + labor force by metro (bls.gov - free)"],vars:["avg_commute_time","population_per_sq_km"],join:["median_household_income","housing_cpi","pct_bachelors"],sc:{emotional:6,relatability:8,surprise:7,tension:5,visual:6,data_ready:7,originality:6},vs:63,tags:"remote work share office vacancy metro San Francisco 37% 34% Dallas 21% 22% r=0.81 structural shift not temporary Stanford WFH CBRE office vacancy downtown empty geography"}',
',{id:"xref_labor_productivity_vs_compensation_growth_1948_2024",title:"US labor productivity vs. compensation growth 1948-2024 - the great decoupling",sub:"1948-1973: labor productivity grew 96.7%, compensation grew 91.3% - near-perfect coupling. 1973-2024: productivity grew 246%, compensation grew 115%. The 131-point gap represents the share of productivity gains that did not go to workers. The decoupling started exactly in 1973 and has continued without interruption.",type:"CHART",geo:"us_national",fmt:"Line chart",tbl:"EPI analysis of BLS productivity data + BEA compensation data 1948-2024 (public)",section:"Labor Force",ext:["FRED: any national economic time series (fred.stlouisfed.org - free API)","BLS national data: employment, wages, CPI (bls.gov - free API)"],vars:["manufacturing_hourly_wages_state","median_household_income"],join:["pct_over_200k","manufacturing_employment_trend","rd_pct_gdp"],sc:{emotional:8,relatability:7,surprise:8,tension:7,visual:7,data_ready:8,originality:4},vs:72,tags:"labor productivity compensation growth 1948 2024 1948-1973 96.7% 91.3% 1973-2024 246% 115% 131-point gap decoupling 1973 uninterrupted EPI BLS BEA great decoupling workers share"}',
